mapper.select:
/* SQL ID : ReshAnsrDAO.listReshTextQstnAnswer 설 명 : 설문 문항별 서술형 응답 리스트 조회 */ SELECT A.ETC_OPNN , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS USERNM , ROW_NUMBER() OVER () AS RNUM FROM TB_LMS_SRVY_RSPNS A WHERE A.SRVY_QSTN_ID = #{reschQstnCd} AND A.USER_ID != ''
AND A.USER_ID IN (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N')
GROUP BY A.ETC_OPNN, A.USER_ID

/* SQL ID : ReshAnsrDAO.listReshQstnScaleAnswerStatus 설 명 : 설문 문항별 척도형 응답현황 */ SELECT A.SRVY_QSTN_ID , A.SRVY_VWITM_ID , A.RESCH_QSTN_ITEM_TITLE , MAX(IF(A.SCALE_ODR = 1, A.EVL_TTL, NULL)) AS SCALE_TITLE_1 , MAX(IF(A.SCALE_ODR = 1, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_1 , MAX(IF(A.SCALE_ODR = 1, A.JOIN_CNT, NULL)) AS JOIN_CNT_1 , MAX(IF(A.SCALE_ODR = 1, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_1 , MAX(IF(A.SCALE_ODR = 2, A.EVL_TTL, NULL)) AS SCALE_TITLE_2 , MAX(IF(A.SCALE_ODR = 2, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_2 , MAX(IF(A.SCALE_ODR = 2, A.JOIN_CNT, NULL)) AS JOIN_CNT_2 , MAX(IF(A.SCALE_ODR = 2, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_2 , MAX(IF(A.SCALE_ODR = 3, A.EVL_TTL, NULL)) AS SCALE_TITLE_3 , MAX(IF(A.SCALE_ODR = 3, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_3 , MAX(IF(A.SCALE_ODR = 3, A.JOIN_CNT, NULL)) AS JOIN_CNT_3 , MAX(IF(A.SCALE_ODR = 3, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_3 , MAX(IF(A.SCALE_ODR = 4, A.EVL_TTL, NULL)) AS SCALE_TITLE_4 , MAX(IF(A.SCALE_ODR = 4, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_4 , MAX(IF(A.SCALE_ODR = 4, A.JOIN_CNT, NULL)) AS JOIN_CNT_4 , MAX(IF(A.SCALE_ODR = 4, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_4 , MAX(IF(A.SCALE_ODR = 5, A.EVL_TTL, NULL)) AS SCALE_TITLE_5 , MAX(IF(A.SCALE_ODR = 5, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_5 , MAX(IF(A.SCALE_ODR = 5, A.JOIN_CNT, NULL)) AS JOIN_CNT_5 , MAX(IF(A.SCALE_ODR = 5, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_5 , MAX(IF(A.SCALE_ODR = 6, A.EVL_TTL, NULL)) AS SCALE_TITLE_6 , MAX(IF(A.SCALE_ODR = 6, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_6 , MAX(IF(A.SCALE_ODR = 6, A.JOIN_CNT, NULL)) AS JOIN_CNT_6 , MAX(IF(A.SCALE_ODR = 6, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_6 , MAX(IF(A.SCALE_ODR = 7, A.EVL_TTL, NULL)) AS SCALE_TITLE_7 , MAX(IF(A.SCALE_ODR = 7, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_7 , MAX(IF(A.SCALE_ODR = 7, A.JOIN_CNT, NULL)) AS JOIN_CNT_7 , MAX(IF(A.SCALE_ODR = 7, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_7 , MAX(IF(A.SCALE_ODR = 8, A.EVL_TTL, NULL)) AS SCALE_TITLE_8 , MAX(IF(A.SCALE_ODR = 8, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_8 , MAX(IF(A.SCALE_ODR = 8, A.JOIN_CNT, NULL)) AS JOIN_CNT_8 , MAX(IF(A.SCALE_ODR = 8, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_8 , MAX(IF(A.SCALE_ODR = 9, A.EVL_TTL, NULL)) AS SCALE_TITLE_9 , MAX(IF(A.SCALE_ODR = 9, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_9 , MAX(IF(A.SCALE_ODR = 9, A.JOIN_CNT, NULL)) AS JOIN_CNT_9 , MAX(IF(A.SCALE_ODR = 9, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_9 , MAX(IF(A.SCALE_ODR = 10, A.EVL_TTL, NULL)) AS SCALE_TITLE_10 , MAX(IF(A.SCALE_ODR = 10, REPLACE(CONVERT(IF(A.RNUM = 1, 100 - ACUM_RATIO, A.RATIO), CHAR), '.0', ''), NULL)) AS RATIO_10 , MAX(IF(A.SCALE_ODR = 10, A.JOIN_CNT, NULL)) AS JOIN_CNT_10 , MAX(IF(A.SCALE_ODR = 10, A.TOT_JOIN_CNT, NULL)) AS TOT_JOIN_CNT_10 FROM ( SELECT A.SRVY_QSTN_ID , A.SRVY_VWITM_ID , A.RESCH_QSTN_ITEM_TITLE , A.VWITM_SEQ , A.SRVY_SCALE_CD , A.EVL_TTL , A.JOIN_CNT , A.TOT_JOIN_CNT , A.SCALE_ODR , ROW_NUMBER() OVER(PARTITION BY A.SRVY_QSTN_ID, A.SRVY_VWITM_ID ORDER BY A.JOIN_CNT DESC, A.SCALE_ODR DESC) RNUM , ROUND(A.JOIN_CNT / IF(A.TOT_JOIN_CNT=0,1,A.TOT_JOIN_CNT) * 100, 1) AS RATIO , SUM(ROUND(A.JOIN_CNT / IF(A.TOT_JOIN_CNT=0,1,A.TOT_JOIN_CNT) * 100, 1)) OVER(PARTITION BY A.SRVY_QSTN_ID, A.SRVY_VWITM_ID ORDER BY A.JOIN_CNT) - ROUND(A.JOIN_CNT / IF(A.TOT_JOIN_CNT=0,1,A.TOT_JOIN_CNT) * 100, 1) AS ACUM_RATIO FROM ( SELECT D.SRVY_QSTN_ID , D.SRVY_VWITM_ID , D.RESCH_QSTN_ITEM_TITLE , D.VWITM_SEQ , E.SRVY_SCALE_CD , E.EVL_TTL , COUNT(F.SRVY_RSPNS_ID) OVER(PARTITION BY D.SRVY_QSTN_ID, D.SRVY_VWITM_ID, E.SRVY_SCALE_CD) JOIN_CNT , COUNT(F.SRVY_RSPNS_ID) OVER(PARTITION BY D.SRVY_QSTN_ID, D.SRVY_VWITM_ID) TOT_JOIN_CNT , E.SCALE_ODR FROM SRVY_VWITM D JOIN TB_LMS_RESCH_SCALE E ON D.SRVY_QSTN_ID = E.SRVY_QSTN_ID LEFT JOIN TB_LMS_SRVY_RSPNS F ON D.SRVY_QSTN_ID = F.SRVY_QSTN_ID AND D.SRVY_VWITM_ID = F.SRVY_VWITM_ID AND E.SRVY_SCALE_CD = F.SRVY_SCALE_CD AND F.USER_ID != ''
AND F.USER_ID IN (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N')
WHERE D.SRVY_QSTN_ID = #{reschQstnCd} ) A GROUP BY A.SRVY_QSTN_ID , A.SRVY_VWITM_ID , A.RESCH_QSTN_ITEM_TITLE , A.VWITM_SEQ , A.SRVY_SCALE_CD , A.EVL_TTL , A.JOIN_CNT , A.TOT_JOIN_CNT , A.SCALE_ODR ) A GROUP BY A.SRVY_QSTN_ID , A.SRVY_VWITM_ID , A.RESCH_QSTN_ITEM_TITLE , A.VWITM_SEQ ORDER BY A.VWITM_SEQ

mapper.insert:
    	/*
             SQL ID : ReshAnsrDAO.insertReshAnsr
             	설  명 : 설문 응답 등록
         */
         INSERT INTO TB_LMS_SRVY_RSPNS (
         	  SRVY_RSPNS_ID
			, USER_ID
			, SRVY_ID
			, SRVY_QSTN_ID
			, SRVY_VWITM_ID
			, SRVY_SCALE_CD
			, ETC_OPNN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         )
         VALUES (
         	  #{reschAnsrCd}
         	, #{userId}
         	, #{reschCd}
         	, #{reschQstnCd}
         	, #{reschQstnItemCd}
         	, #{reschScaleCd}
         	, #{etcOpinion}
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
         )

mapper.delete:
	/*
         SQL ID : ReshAnsrDAO.delReshAnsr
         	설  명 : 설문 응답 삭제
     */
	DELETE FROM TB_LMS_SRVY_RSPNS
	 WHERE 1=1

	   AND SRVY_RSPNS_ID = #{reschAnsrCd}


	   AND SRVY_ID = #{reschCd}


	   AND SRVY_QSTN_ID = #{reschQstnCd}


	   AND USER_ID = #{userId}

	/*
         SQL ID : ReshAnsrDAO.delReshJoinUser
         	설  명 : 설문 참여자 삭제
     */
     DELETE FROM TB_LMS_SRVY_PTCP
      WHERE 1= 1
        AND SRVY_ID = #{reschCd}

        AND USER_ID = #{userId}

mapper.select:
/* SQL ID : ReshAnsrDAO.listHomeReshJoinUser 설 명 : 홈페이지 설문 참여자 목록 조회(미참여자 포함) */ SELECT A.SRVY_ID AS reschCd , B.USER_ID AS userId , E.CNTN_DVC_TYCD AS deviceTypeCd , IFNULL((SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'CNTN_DVC_TYCD' AND CD = E.CNTN_DVC_TYCD), '') AS deviceTypeNm , E.FRST_INQ_DTTM AS regDttm , C.DEPT_CD AS deptCd , C.DEPTNM AS deptNm , C.USERNM AS userNm , D.USER_ID AS userId , IF(E.USER_ID IS NULL, 'N', 'Y') AS joinYn , ROW_NUMBER() OVER (ORDER BY C.USERNM) AS lineNo , COUNT(1) OVER() AS totalCnt FROM TB_LMS_SRVY A JOIN TB_LMS_USER_AUTHRT B ON A.JOIN_TRGT REGEXP B.USER_AUTHRT_ID JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_USER_ACNT D ON C.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' LEFT JOIN TB_LMS_SRVY_PTCP E ON E.SRVY_ID = A.SRVY_ID AND E.USER_ID = D.USER_ID WHERE A.SRVY_ID = #{reschCd}
AND ( LOWER(C.DEPT_CD) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(B.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND E.USER_ID IS NOT NULL
AND E.USER_ID IS NULL
GROUP BY A.SRVY_ID , B.USER_ID , E.CNTN_DVC_TYCD , E.FRST_INQ_DTTM , C.DEPT_CD , C.DEPTNM , C.USERNM , D.USER_ID , E.USER_ID ORDER BY C.USERNM LIMIT #{firstIndex}, #{listScale}

/* SQL ID : ReshAnsrDAO.listReshAnswer 설 명 : 설문 답변 목록 */ SELECT A.SRVY_ID , A.USER_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS USERNM , D.RESCH_PAGE_CD , B.SRVY_QSTN_ID , B.SRVY_VWITM_ID , NVL(B.ETC_OPNN, E.RESCH_QSTN_ITEM_TITLE) AS RESCH_QSTN_ITEM_TITLE , F.EVL_TTL , F.SRVY_SCALE_CD FROM TB_LMS_SRVY_PTCP A JOIN TB_LMS_SRVY_RSPNS B ON A.SRVY_ID = B.SRVY_ID AND A.USER_ID = B.USER_ID JOIN TB_LMS_SRVY_QSTN C ON B.SRVY_QSTN_ID = C.SRVY_QSTN_ID JOIN TB_LMS_RESCH_PAGE D ON C.RESCH_PAGE_CD = D.RESCH_PAGE_CD LEFT JOIN SRVY_VWITM E ON B.SRVY_QSTN_ID = E.SRVY_QSTN_ID AND B.SRVY_VWITM_ID = E.SRVY_VWITM_ID LEFT JOIN TB_LMS_RESCH_SCALE F ON F.SRVY_QSTN_ID = B.SRVY_QSTN_ID AND F.SRVY_SCALE_CD = B.SRVY_SCALE_CD WHERE A.SRVY_ID = #{reschCd} AND A.USER_ID != ''
AND A.USER_ID = #{userId}
ORDER BY A.USER_ID, D.RESCH_PAGE_ODR, C.RESCH_QSTN_ODR

mapper.update:
    	/*
             SQL ID : ReshAnsrDAO.updateReshUserMemo
             	설  명 : 설문 메모 수정
         */
         INSERT INTO TB_LMS_SRVY_PTCP (
         	  SRVY_ID
			, USER_ID
			, STD_ID
			, EVLYN
			, SCR_MEMO
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         ) VALUES (
         	  #{reschCd}
         	, #{userId}
         	, #{stdNo}
         	, 'N'
         	, #{profMemo}
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
         )
         ON DUPLICATE KEY
         UPDATE
         	SCR_MEMO = #{profMemo}

mapper.select:
/* SQL ID : ReshAnsrDAO.listReshJoinUserByEzGrader 설 명 : 설문 참여자 리스트 조회(EZ-Grader) */ SELECT * FROM ( SELECT A.SRVY_ID AS reschCd , B.USER_ID AS userId , B.STD_ID AS stdNo , C.DEPTNM AS deptNm , C.USERNM AS userNm , D.USER_ID AS userId , (SELECT MAX(FRST_INQ_DTTM) FROM TB_LMS_SRVY_RSPNS WHERE SRVY_ID = A.SRVY_ID AND USER_ID = B.USER_ID GROUP BY USER_ID) AS regDttm , IFNULL(E.SCR, 0) AS SCR , E.SCR_MEMO AS profMemo , IFNULL((SELECT 'Y' FROM TB_LMS_SRVY_RSPNS WHERE SRVY_ID = A.SRVY_ID AND USER_ID = B.USER_ID GROUP BY USER_ID), 'N') AS joinYn , IFNULL((SELECT IF(MAX(FRST_INQ_DTTM) > (SELECT RESCH_END_DTTM FROM TB_LMS_SRVY WHERE SRVY_ID = A.SRVY_ID), 'AFTER', 'JOIN') FROM TB_LMS_SRVY_RSPNS WHERE SRVY_ID = A.SRVY_ID AND USER_ID = B.USER_ID GROUP BY USER_ID), 'NOTJOIN') AS submitType , COUNT(1) OVER() AS totalCnt FROM TB_LMS_RESCH_CRE_CRS_RLTN A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_USER_ACNT D ON C.USER_ID = D.USER_ID AND B.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' LEFT JOIN TB_LMS_SRVY_PTCP E ON B.USER_ID = E.USER_ID AND A.SRVY_ID = E.SRVY_ID WHERE A.SRVY_ID = #{reschCd} ) AA
WHERE AA.submitType = #{searchKey}
ORDER BY AA.userId
ORDER BY AA.userNm
ORDER BY AA.joinYn DESC, AA.regDttm
